import { type ReactNode } from 'react';
/**
 * Describes the form control state given its current value.
 * @public
 */
export type FormControlValueState = 'valid' | 'error';
/**
 * Describes an enhanced representation of a control validity state and hints about its error for the end user.

* @public
*/
export type FormControlState = {
    state: FormControlValueState;
    hint?: ReactNode;
} | FormControlValueState;
/**
 * Provides a property interface for form controls requiring a validation state.
 * @public
 */
export interface FormControlStateProps {
    controlState?: FormControlState;
}
